script:
export const meta = {
  name: 'pass8-assess',
  description: 'Pass-8 adversarial assessment: 7 dimension assessors + self-refutation',
  phases: [{ title: 'Assess' }, { title: 'Refute' }],
}

const REPO = '/Users/[REDACTED]/hc-assay'

const FINDINGS_SCHEMA = {
  type: 'object',
  additionalProperties: false,
  required: ['findings'],
  properties: {
    findings: {
      type: 'array',
      items: {
        type: 'object',
        additionalProperties: false,
        required: ['id', 'severity', 'title', 'location', 'claim', 'why_real', 'suggested_fix'],
        properties: {
          id: { type: 'string', description: 'short stable id, e.g. K-SEC-1' },
          severity: { type: 'string', enum: ['critical', 'high', 'medium', 'low'] },
          title: { type: 'string' },
          location: { type: 'string', description: 'file:line or file:symbol' },
          claim: { type: 'string', description: 'the precise, FALSIFIABLE defect claim' },
          why_real: { type: 'string', description: 'evidence it is a genuine production-readiness defect, not a nit' },
          suggested_fix: { type: 'string' },
        },
      },
    },
  },
}

const COMMON = `You are an adversarial production-readiness assessor for the hc-assay engine at ${REPO} (a dataset-agnostic, data-sovereign empirical-ML/methodology engine; optional backends are import-guarded; transcripts are committed as provenance and scrubbed of operator PII intentionally). This codebase has already survived SEVEN hardening passes — so easy findings are gone. Report ONLY genuine, concrete, FALSIFIABLE production-readiness defects with a real failure mode; no style nits, no speculative "could be nicer". Each finding needs a file:line/symbol location and a claim someone could disprove by reading the code. Prefer depth over breadth. If a dimension is genuinely clean, return few or zero findings — do NOT invent. Read the actual code (use Read/Grep/Bash; run tests if useful — note: use "python -m pytest", and "source .venv/bin/activate").`

const DIMENSIONS = [
  { key: 'PRIV', label: 'privacy/PII (PRIORITY)', focus: `PRIORITY DIMENSION — privacy has yielded confirmed findings 3 passes running. Re-probe scripts/capture_transcripts.py AND the committed transcripts/ corpus for ANY remaining operator-identity vector or NEW class of leaked secret/PII. Specifically scrutinize the pass-7 additions: the separator-flexible GitHub-handle regex (over-redaction? catastrophic-backtracking / ReDoS on adversarial input? does it corrupt legitimate content?), the IGNORECASE per-token name redaction (over-redaction of common words that happen to match a name token?), idempotency of re-scrubbing, and whether import-time pattern derivation (git/env) can silently produce ZERO patterns in some run context (CI, clean checkout) and thus scrub nothing. Also: are there OTHER secret/PII shapes (API endpoints, internal hostnames, IPs, absolute paths revealing identity) not yet covered? grep the corpus to back claims.` },
  { key: 'FIXREG', label: 'pass-7 fix-regression audit', focus: `Diff and audit pass-7's OWN changes (git log main, the J-001..J-008 fixes in scripts/capture_transcripts.py, src/assay_engine/observability/tracking.py, .github/workflows/ci.yml, tests/integration/test_reasoning_drain.py) for FOLLOW-ON defects — exactly as pass-7 caught J-001 as a regression of pass-6's CV-O-1. Did any pass-7 fix introduce a new bug, weaken an invariant, make a test non-discriminating, or have an untested edge? Check the MLflow TOCTOU re-fetch (does the broad except swallow real errors / infinite states?), the NUL-byte binary classifier (NUL-free binary now corrupted?), the --no-build-isolation CI change (does it actually build?), the _assert_transient helper.` },
  { key: 'SEC', label: 'security/data-sovereignty', focus: `Data-sovereignty enforcement (local-URI guards, loopback-only, no metered/remote calls), injection, unsafe deserialization (pickle/yaml/json), path traversal, SSRF in any URL handling, secret handling in env/config, the local-URI guard completeness across all backends.` },
  { key: 'CONC', label: 'correctness/concurrency/reliability', focus: `Race conditions, the reasoning thread pool, cancellation/timeout correctness, resource leaks (fds, connections, subprocesses, threads), error-path leaks, retry/backoff correctness, partial-failure handling, idempotency of run_study.` },
  { key: 'METH', label: 'methodology integrity', focus: `The pre-registration firewall / HARKing prevention, canonical_hypothesis_digest binding of decision-bearing fields, confirm primitives, direction/locked-param resolution, provenance trail integrity (append-only, keyed), any way a caller could silently subvert the methodology guarantees.` },
  { key: 'OPS', label: 'ops/packaging/supply-chain', focus: `Packaging (pyproject, wheel contents, ADR-0006 dependency-free core), lockfile/hash integrity, CI gates completeness (can a job pass vacuously?), the license gate, SBOM, version pinning, reproducibility, dependency bounds.` },
  { key: 'OBS', label: 'observability/provenance', focus: `Tracing/metrics/tracking correctness, MLflow lifecycle (orphaned runs, status), structured logging (does it leak secrets/PII into logs?), env-var parsing, provenance artifact completeness and integrity.` },
]

phase('Assess')
const refuteSchema = {
  type: 'object', additionalProperties: false,
  required: ['verdict', 'reasoning'],
  properties: { verdict: { type: 'string', enum: ['STANDS', 'REFUTED'] }, reasoning: { type: 'string' } },
}

const perDim = await parallel(
  DIMENSIONS.map((d) => () =>
    agent(`${COMMON}\n\nYOUR DIMENSION: ${d.label}.\n${d.focus}`, {
      label: `assess:${d.key}`, phase: 'Assess', schema: FINDINGS_SCHEMA,
    }).then((r) => ({ dim: d.key, findings: (r && r.findings) || [] }))
  )
)

const all = perDim.filter(Boolean).flatMap((r) => r.findings.map((f) => ({ ...f, dim: r.dim })))
log(`Assess: ${all.length} raw findings across ${DIMENSIONS.length} dimensions`)

// adversarial self-refutation: one skeptic per finding, tasked to DISPROVE it.
phase('Refute')
const judged = await parallel(
  all.map((f) => () =>
    agent(
      `You are an adversarial skeptic. Try to REFUTE this pass-8 finding about ${REPO} by reading the actual code. A finding is REFUTED if it is a false positive, already-mitigated, out-of-scope by design (dataset-agnostic engine, optional import-guarded backends, intentionally-committed scrubbed transcripts, data-sovereign on-box), or not a real production defect. Default to REFUTED if the claim does not hold up. Use "python -m pytest" / "source .venv/bin/activate" if you test.\n\nFINDING ${f.id} (${f.severity}, dim ${f.dim}): ${f.title}\nLocation: ${f.location}\nClaim: ${f.claim}\nWhy real: ${f.why_real}`,
      { label: `refute:${f.id}`, phase: 'Refute', schema: refuteSchema }
    ).then((v) => ({ ...f, refute: v }))
  )
)

const survivors = judged.filter(Boolean).filter((f) => f.refute && f.refute.verdict === 'STANDS')
const refuted = judged.filter(Boolean).filter((f) => !f.refute || f.refute.verdict === 'REFUTED')
log(`Self-refutation: ${survivors.length} STAND, ${refuted.length} refuted`)
const bySev = (arr) => ['critical', 'high', 'medium', 'low'].map((s) => `${s}:${arr.filter((f) => f.severity === s).length}`).join(' ')
log(`Survivors by severity — ${bySev(survivors)}`)
return { survivors, refuted_ids: refuted.map((f) => ({ id: f.id, dim: f.dim, why: f.refute && f.refute.reasoning })) }
